import { useState, useEffect } from "react";
import "./Recruitment.css";   // keep – but will be neutralized by isolation
import "./Designations.css";  // MUST be last


function Designations() {
  const [title, setTitle] = useState("");
  const [list, setList] = useState([]);
  const [isEditing, setIsEditing] = useState(false);
  const [editId, setEditId] = useState(null);

  // Load from localStorage
  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem("designations")) || [];
    setList(saved);
  }, []);

  // Save helper
  const saveToStorage = (data) => {
    localStorage.setItem("designations", JSON.stringify(data));
  };

  // Create
  const handleCreate = () => {
    if (!title.trim()) return alert("Please enter designation");

    const exists = list.some(
      (d) => d.title.toLowerCase() === title.toLowerCase()
    );
    if (exists) return alert("This designation already exists");

    const newItem = { id: Date.now(), title };
    const updated = [...list, newItem];

    setList(updated);
    saveToStorage(updated);
    setTitle("");
  };

  // Delete
  const handleDelete = (id) => {
    if (!window.confirm("Are you sure you want to delete this role?")) return;

    const updated = list.filter((d) => d.id !== id);
    setList(updated);
    saveToStorage(updated);
  };

  // Edit
  const handleEdit = (designation) => {
    setIsEditing(true);
    setEditId(designation.id);
    setTitle(designation.title);
  };

  // Update
  const handleUpdate = () => {
    if (!title.trim()) return alert("Please enter designation");

    const exists = list.some(
      (d) =>
        d.title.toLowerCase() === title.toLowerCase() && d.id !== editId
    );
    if (exists) return alert("This designation already exists");

    const updated = list.map((d) =>
      d.id === editId ? { ...d, title } : d
    );

    setList(updated);
    saveToStorage(updated);

    setIsEditing(false);
    setEditId(null);
    setTitle("");
  };

  // Cancel
  const cancelEdit = () => {
    setIsEditing(false);
    setEditId(null);
    setTitle("");
  };

  return (
    <div className="designation-isolated">
      <div className="designation-page">
        <h2>Generate Employee Designation</h2>

        {/* ========= FORM CARD ========= */}
        <div className="designation-form-card">
          <div className="designation-form-row">
            <input
              type="text"
              placeholder="Enter Designation e.g. Manager"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              className="designation-input"
            />

            {!isEditing ? (
              <button
                type="button"
                onClick={handleCreate}
                className="designation-create-btn"
              >
                Create
              </button>
            ) : (
              <div className="designation-edit-actions">
                <button
                  type="button"
                  onClick={handleUpdate}
                  className="designation-update-btn"
                >
                  Update
                </button>

                <button
                  type="button"
                  onClick={cancelEdit}
                  className="designation-cancel-btn"
                >
                  Cancel
                </button>
              </div>
            )}
          </div>
        </div>

        {/* ========= TABLE CARD ========= */}
        <div className="designation-table-card">
          <table className="designation-table">
            <thead>
              <tr>
                <th>S.No</th>
                <th>Designation Title</th>
                <th>Action</th>
              </tr>
            </thead>

            <tbody>
              {list.length === 0 ? (
                <tr>
                  <td colSpan="3" className="no-data">
                    No Designations Created Yet
                  </td>
                </tr>
              ) : (
                list.map((d, index) => (
                  <tr key={d.id}>
                    <td>{index + 1}</td>
                    <td>{d.title}</td>
                    <td className="action-cell">
                      <button
                        type="button"
                        className="edit-btn"
                        onClick={() => handleEdit(d)}
                      >
                        Edit
                      </button>

                      <button
                        type="button"
                        className="delete-btn"
                        onClick={() => handleDelete(d.id)}
                      >
                        Delete
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

export default Designations;
